# Bulk upsert all translations
now = Time.current
rows = []
translation_data.each do |locale, categories|
  categories.each do |category, pairs|
    pairs.each do |key, value|
      rows << { locale: locale, category: category, key: key, value: value, created_at: now, updated_at: now }
    end
  end
end

ContentTranslation.upsert_all(rows, unique_by: [:locale, :category, :key])
puts "Seeded #{ContentTranslation.count} content translations."
